import{_ as e,o,c as a,Q as r}from"./chunks/framework.3daba8ea.js";const h=JSON.parse('{"title":"docker问题","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Docker/进阶/docker问题.md","filePath":"packages/doc/src/DevOps/Docker/进阶/docker问题.md","lastUpdated":1702458087000}'),c={name:"doc/DevOps/Docker/进阶/docker问题.md"},d=r('<h1 id="docker问题" tabindex="-1">docker问题 <a class="header-anchor" href="#docker问题" aria-label="Permalink to &quot;docker问题&quot;">​</a></h1><h2 id="_1-docker-提示-an-available-non-overlapping-ipv4-address" tabindex="-1">1.docker 提示 an available, non-overlapping IPv4 address <a class="header-anchor" href="#_1-docker-提示-an-available-non-overlapping-ipv4-address" aria-label="Permalink to &quot;1.docker 提示 an available, non-overlapping IPv4 address&quot;">​</a></h2><p>开启环境的时候提示ERROR:could not find an available, non-overlapping IPv4 address pool among the defaults to assign to the network 使用docker network ls | wc -l 查看network数量 docker network prune关闭未使用的网络</p><p><a href="https://cloud.tencent.com/developer/section/1091927" target="_blank" rel="noreferrer">https://cloud.tencent.com/developer/section/1091927</a></p><p>这是因为<code>Docker</code>默认支持<code>30</code>个不同的自定义<code>bridge</code>网络，如果超过这个限制，就会提示上面的错误。你可以使用命令<code>docker network ls</code>来查看你创建的网络，然后通过命令<code>docker network prune</code>来移除没有使用的网络。</p>',5),t=[d];function n(s,l,p,i,k,_){return o(),a("div",null,t)}const u=e(c,[["render",n]]);export{h as __pageData,u as default};
